<template>
    <div class="flex items-center justify-center min-h-screen">
        <div class="glass-card p-8 text-center max-w-xl mx-4 w-full sm:w-auto">
            <h1 class="text-3xl font-bold mb-4 text-white">Oh no!</h1>
            <p class="text-lg mb-6 text-white">The builder dudes are still hammering away at this page—grab a hard hat and check back soon!</p>
            <router-link to="/" class="bg-[#532B88] text-white px-6 py-3 rounded-full hover:bg-[#2F184B] transition duration-300 text-center text-sm sm:text-base btn">
                Go back
            </router-link>
        </div>
    </div>

    <div class="container">
        <img src="@/assets/construction/brick.png" class="floating">
        <img src="@/assets/construction/brick.png" class="floating">
        <img src="@/assets/construction/brick.png" class="floating">
        <img src="@/assets/construction/brick.png" class="floating">
        <img src="@/assets/construction/shovel.png" class="floating">
        <img src="@/assets/construction/shovel.png" class="floating">
        <img src="@/assets/construction/pickaxe.png" class="floating">
        <img src="@/assets/construction/pickaxe.png" class="floating">
    </div>
</template>
<style scoped>
.container {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: -1;
    overflow: hidden;
}

img {
    width: 50px;
    height: 50px;
    position: absolute;
    animation: float 40s linear infinite;
}

@keyframes float {
    0% { transform: translate(0, 0); }
    25% { transform: translate(100px, -50px); }
    50% { transform: translate(-100px, 100px); }
    75% { transform: translate(50px, -100px); }
    100% { transform: translate(0, 0); }
}
</style>
<script>
export default {
    mounted() {
        const images = document.querySelectorAll('.floating');
        images.forEach(img => {
            const startX = Math.random() * window.innerWidth;
            const startY = Math.random() * window.innerHeight;
            const duration = 40 + Math.random() * 10;
            img.style.left = `${startX}px`;
            img.style.top = `${startY}px`;
            img.style.animationDuration = `${duration}s`;
            img.style.animationDirection = Math.random() > 0.5 ? 'normal' : 'reverse';
        });
    }
}
</script>
