<template>
    <div class="mt-[100px] glass-card mx-auto">
        <h2 class="text-xl md:text-2xl lg:text-3xl xl:text-4xl mb-4 title-color">{{ project.title }}</h2>
        <div class=" p-4 md:p-6 flex flex-col md:flex-row items-center justify-center">
            <iframe :src="project.url" class="iframe-style md:mr-6 mb-4 md:mb-0"></iframe>
            <div class="text-content">
                <div class="text-sm md:text-base lg:text-lg xl:text-xl mb-4" v-html="formattedDesc"></div>
                <p class="text-sm md:text-base lg:text-lg xl:text-xl mb-4">Date: {{ project.date }}</p>
                <div class="btn flex gap-[20px] w-[200px] mx-auto" v-if="project.github" @click="visitLink"><img src="@/assets/images/githublogo.svg" class="w-8 h-8">View source</div>
            </div>
        </div>
    </div>

  </template>
  
  <script>
  import projects from '@/data/projects';
  
  export default {
    data() {
      return {
        project: null,
        projectIndex: null,
      };
    },
    computed: {
      formattedDesc() {
        return this.project.desc.replace(/\n/g, '<br>');
      },
    },
    created() {
      this.projectIndex = this.$route.params.id;
      this.project = projects[this.projectIndex];
    },
    methods: {
      visitLink() {
        window.open(this.project.github, '_blank');
      },
    },
  };
  </script>
  
  <style scoped>
  .glass-card {
    padding: 16px;
    max-width: 95%; /* Less crowded on mobile */
  }


  @media (min-width: 768px) {
    .glass-card {
      padding: 24px;
      max-width: 85%; /* Increased width on tablets and above */
    }
  }
  
  @media (min-width: 1500px) {
    .glass-card {
      padding: 32px;
      max-width: 70%; /* Larger width for very large screens */
    }
  }
  
  .iframe-style {
    border: none;
    border-radius: 8px;
    aspect-ratio: 16/9;
    max-height: 400px;
    width: 100%;
  }
  
  .text-content {
    display: flex;
    flex-direction: column;
    text-align: center; /* Center-align text on mobile */
  }
  
  .title-color {
    color: #9B72CF;
    text-align: center;
  }
  
  @media (min-width: 700px) {
    .glass-card {
      flex-direction: row;
      align-items: center;
      text-align: left; /* Align text to the left on larger screens */
    }
  
    .iframe-style {
      max-width: 50%;
      margin-right: 1.5rem;
    }
  
    .text-content {
      text-align: left;
    }
  }
  </style>
  