<template>
  <div class="backgroundimg"></div>
  <effects/>
  <navigation :class="{hidenavbar: !navbar}"/>

  <div class="fade">
    <router-view/>
  </div>
</template>


<script>
import navigation from '@/components/navigation.vue'
import effects from './components/effects.vue';

export default {
  components: {navigation, effects},
  data() {
    return {
      navbar: false
    };
  },
  created() {
    if (this.$route.path !== '/') {
      this.navbar = true;
    }
  },
  watch: {
    $route(to, from) {
      if (to.path === '/') {
        this.navbar = false;
      } else {
        this.navbar = true;
      }
    },
  }

}
</script>


<style>
.hidenavbar{
  opacity: 0;
}
</style>
