<template>
  <div class="container">
    <img 
      v-for="(star, index) in stars" 
      :key="star.id" 
      src="@/assets/images/star.svg" 
      class="star" 
      :class="{ shine: star.isShining }"
      :style="{ 
        left: `${star.left}%`,
        top: `${star.top}%`,
        width: `${star.size}px`,
        height: `${star.size}px`,
        animationDelay: `${star.delay}s`, 
      }"
    />
  </div>

  <div class="cont">
    <span  :class="{ fling: fling, 'shooting-star': true }"  :style="shootstar" @animationend="resetShootingStar"></span>
  </div>
</template>

<script>
export default {
  data() {
    return {
      stars: [],
      shineInterval: null, 
      flingInterval: null,

      fling: false,
      shootstar: {
        left: `${Math.random() * 100}%`,
      }
    };
  },
  created() {
    this.generateStars();
    this.setupInterval();

    window.addEventListener('resize', this.generateStars);
  },
  beforeDestroy() {
    window.removeEventListener('resize', this.generateStars);
    clearInterval(this.shineInterval); 
    clearInterval(this.flingInterval);
  },
  computed: {
  },
  methods: {
    generateStars() {
      const screenWidth = window.innerWidth;
      const screenHeight = window.innerHeight;
      const numberOfStars = Math.floor((screenWidth * screenHeight) / 10000); 
      this.stars = Array.from({ length: numberOfStars }, (_, id) => ({
        id,
        left: Math.random() * 100,
        top: Math.random() * 100,
        size: Math.random() * 10 + 2,
        isShining: false, 
        delay: Math.random() * 2 
      }));
    },
    setupInterval() {
      this.shineInterval = setInterval(() => {
        this.updateShiningStars();
      }, 3000);

      this.flingInterval = setInterval(() => {
        this.fling = true;
      }, 5000);
    },
    updateShiningStars() {
      const numberOfStars = this.stars.length;
      const numberToShine = Math.floor(numberOfStars * 0.1);

      this.stars.forEach(star => star.isShining = false);

      const indices = Array.from({ length: numberOfStars }, (_, i) => i);
      for (let i = 0; i < numberToShine; i++) {
        const randomIndex = Math.floor(Math.random() * indices.length);
        const starIndex = indices.splice(randomIndex, 1)[0];
        this.stars[starIndex].isShining = true;
      }
    },
    resetShootingStar() {
      this.shootstar.left = `${Math.random() * 100}%`;
      this.fling = false;
    }
  }
};
</script>

<style scoped>
.container {
  position: fixed;
  width: 100%;
  height: 100%;
  top: 0;
  left: 0;
  overflow: hidden;
  z-index: -1;
}

.star {
  position: absolute;
  filter: drop-shadow(0px 0px 20px rgb(255, 255, 255));
}

.shine {
  animation: shine 0.5s ease-in-out;
}

.shooting-star {
  position: fixed;
  top: -10%;
  width: 1px;
  height: 1px;
  background: white;
  border-radius: 100%;
  box-shadow: 0 0 0 4px white;
}

.fling {
  animation: fling 0.5s linear;
}

.shooting-star::before {
  content: '';
  position: absolute;
  top: 50%;
  width: 300px;
  height: 1px;
  background: linear-gradient(90deg, #fff, transparent);
}

@keyframes fling {
  0% {
    transform: rotate(315deg) translate(0);
  }
  100% {
    transform: rotate(315deg) translate(-1000px);
  }
}

@keyframes shine {
  0% {
    opacity: 1;
  }
  50% {
    opacity: 0.3;
  }
  100% {
    opacity: 1;
  }
}

</style>
