<template>
  <div class="mt-[100px] mx-5 py-8 grid gap-8 justify-center auto-rows-auto" style="grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));">
    <div v-for="(project, index) in projects" :key="project.title" class="glass-card p-6 flex flex-col">
      <iframe v-if="project.url" :src="project.url" class="w-full h-48 mb-4" frameborder="0" allowfullscreen></iframe>
      <div class="flex-1">
        <h2 class="text-2xl font-bold mb-2">{{ project.title }}</h2>
        <p class="text-gray-500 mb-4">{{ truncateDesc(project.desc) }}</p>
      </div>
      <div class="flex">
        <router-link :to="`/project/${index}`" class="btn">View Project</router-link>
      </div>
    </div>
  </div>
</template>

<script>
import projects from '@/data/projects';

export default {
  data() {
    return {
      projects,
    };
  },
  methods: {
    truncateDesc(desc) {
      return desc.length > 50 ? `${desc.slice(0, 50)}...` : desc;
    },
  },
};
</script>

